function s(n){try{return new URL(n).hostname.replace("www.","")}catch{return n}}function u(n){try{const{origin:t}=new URL(n);return`https://www.google.com/s2/favicons?domain=${t}&sz=32`}catch{return""}}function i(n){const r=Date.now()-n,o=Math.floor(r/1e3),e=Math.floor(o/60),a=Math.floor(e/60),c=Math.floor(a/24);return o<60?"just now":e<60?`${e}m ago`:a<24?`${a}h ago`:c<7?`${c}d ago`:new Date(n).toLocaleDateString("en-US",{month:"short",day:"numeric",year:c>365?"numeric":void 0})}function f(n,t=150){return!n||n.length<=t?n:n.slice(0,t).trim()+"…"}function w(n){return n.reduce((t,r)=>{const o=r.domain||s(r.url);return t[o]||(t[o]=[]),t[o].push(r),t},{})}function m(n){try{const t=new URL(n),r=t.pathname==="/"?"":t.pathname,o=t.hostname.replace("www.","")+r;return o.length>40?o.slice(0,40)+"…":o}catch{return n}}export{u as a,s as b,i as f,w as g,m as s,f as t};
